#include <bits/stdc++.h>
using namespace std;
int n,a[100005],dp[100005],f[100005],ans=0,cnt=1;
set<int> s;
int main()
{
    while(cin>>a[++n],a[n]);
    n--;
    f[1]=0x3f3f3f3f;
    for(int i=1;i<=n;i++)
    {
        if(a[i]<=f[cnt]) f[++cnt]=a[i];
        else
        {
            int l=1,r=cnt;
            while(l<r)
            {
                int mid=(l+r)>>1;
                if(f[mid]<a[i]) r=mid;
                else l=mid+1;
            }
            f[r]=a[i];
        }
    }
    for(int i=1;i<=n;i++)
    {
        set<int> ::iterator it=s.lower_bound(a[i]);
        if(it==s.end()) s.insert(a[i]);
        else s.erase(it),s.insert(a[i]);
    }
    cout<<cnt-1<<'\n'<<s.size();
    return 0;
}
